use git2::{Delta, DiffOptions, Repository, Signature};

pub struct GitTracker {
    repo: Repository,
}

impl GitTracker {
    pub fn new(project_dir: &Path) -> Result<Self> {
        let repo = Repository::open(project_dir).context("Failed to open git repository")?;
        Ok(Self { repo })
    }

    pub fn snapshot_before(&self, phase: &str) -> Result<String> {
        // Creates commits with Signature::now()
        // Uses repo.index(), index.add_all(), index.write_tree()
        // Calls repo.commit() with tree and parent references
        // Returns commit ID as String
    }

    pub fn compute_changes(&self, before_sha: &str) -> Result<FileChangeSummary> {
        // Uses git2::Oid::from_str() to parse SHA
        // Uses repo.find_commit(oid) and commit.tree()
        // Uses DiffOptions with include_untracked(true)
        // Uses repo.diff_tree_to_workdir_with_index()
        // Iterates with diff.foreach() for Delta::Added, Delta::Modified, Delta::Deleted
    }

    pub fn get_full_diffs(&self, before_sha: &str) -> Result<Vec<FileDiff>> {
        // Similar diff operations but extracts patch content
        // Uses git2::Patch::from_diff() to get individual file patches
        // Uses patch.print() callback for diff content collection
    }

    pub fn head_sha(&self) -> Option<String> {
        // Returns current HEAD SHA if it exists
    }

    fn get_head_commit(&self) -> Option<git2::Commit<'_>> {
        // Uses repo.head() and peel_to_commit()
    }
}
```

**File 2: `/Users/jdsingh/Projects/AI/forge/src/council/merge.rs`**

Key patterns:
```rust
use git2::Repository;

pub struct WorktreeManager {
    repo: Repository,
    repo_path: PathBuf,
}

impl WorktreeManager {
    pub fn new(repo_path: &Path) -> Result<Self> {
        let repo = Repository::open(repo_path)?;
        let repo_path = repo.workdir()
            .map(Path::to_path_buf)
            .or_else(|| repo.path().parent().map(Path::to_path_buf))?;
        Ok(Self { repo, repo_path })
    }
}
```

**Note:** `council/merge.rs` opens `Repository` for context but delegates all git operations to **external shell commands** (`Command::new("git")`), not git2 methods.

### 5. Cargo.toml Dependency

**Confirmed:** git2 is declared in Cargo.toml:
```toml
[dependencies]
git2 = "0.20.4"
```

### Key Patterns & Conventions for Implementation

Based on the codebase analysis, when implementing `LoopGitOps`, you should:

1. **Use git2 types directly:** `Repository`, `Signature`, `Oid`, `Delta`, `DiffOptions`, `Patch`
2. **Return Result<T> with .context():** All public functions return `anyhow::Result<T>` with context enrichment
3. **Signature creation:** `Signature::now("forge", "forge@localhost")?` for automated commits
4. **Index operations:** Use `repo.index()`, `index.add_all()`, `index.write_tree()`
5. **Commit creation:** Pass tree, parent commit refs (empty slice `&[]` for initial commits)
6. **Diff operations:** Use `DiffOptions` with flags like `include_untracked(true)`
7. **String representation:** Convert `Oid` to `String` via `.to_string()`
8. **Lifetime management:** Be aware that `Commit`, `Tree`, etc. have repo lifetimes
9. **Error context:** Use `.with_context(|| format!(...))` for contextual error messages

### Files That Need to Be Created

1. **`src/cmd/autoresearch/loop_runner.rs`** - Should define the `LoopGitOps` trait
2. **`src/cmd/autoresearch/git_ops.rs`** - Should implement `LoopGitOps` using git2

### Expected Trait Signature Pattern

Based on `GitTracker` and `WorktreeManager` patterns, the `LoopGitOps` trait should likely include methods for:
- Opening/creating a repository
- Creating snapshots before iterations
- Computing changes/diffs between commits
- Retrieving commit information (SHA, tree, changes)
- Handling unborn repositories gracefully

