        assert_eq!(
            fs::read_to_string(&kept_path).expect("read kept"),
            "I am kept\n"
        );

        // HEAD must be at the keep commit.
        assert_eq!(
            ops.head_sha().expect("head_sha"),
            keep_sha,
            "HEAD must be at the keep commit after discard"
        );
    }
}

